# Base module with interfaces and abstract classes

interface Drawable:
    def draw(self) -> str: ...

@abstract
class Shape(Drawable):
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"{self.name}: area={self.area()}"

