# Module with enums, structs, and concrete implementations

from shapes_base import Shape, Drawable

enum ShapeKind:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

struct Bounds:
    min_pt: Point
    max_pt: Point

    def __init__(self, min_pt: Point, max_pt: Point):
        self.min_pt = min_pt
        self.max_pt = max_pt

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing circle '{self.name}' with radius {self.radius}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return f"Drawing rectangle '{self.name}' {self.width}x{self.height}"

def create_bounds(center: Point, size: float) -> Bounds:
    half: float = size / 2.0
    return Bounds(
        Point(center.x - half, center.y - half),
        Point(center.x + half, center.y + half)
    )
